const props = withDefaults(defineProps<{
  name: string
  size?: number | string
  color?: string
}>(), {
  size: 24,
  color: '#000000',
})

const sizeVal = computed(() => {
  const s = props.size
  return typeof s === 'number' ? `${s}px` : (String(s).endsWith('px') ? String(s) : `${s}px`)
})

const bgImage = computed(() => {
  const path = PATHS[props.name]
  if (!path) return ''
  const color = (props.color || '#000000').replace(/#/g, '%23')
  const uri = `data:image/svg+xml;charset=utf-8,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 256 256'%3E%3Cpath fill='${color}' d='${path}'/%3E%3C/svg%3E`
  return `url("${uri}")`
})
</script>
